def get_current_user_from_context(info):
    """Safely extract the current user from the request context."""
    request = info.context.get("request")
    if request and hasattr(request, "state") and hasattr(request.state, "current_user"):
        return request.state.current_user
    return None


def sanitize_string(value, max_length=1000):
    """Sanitize string output to prevent injection in responses."""
    if value is None:
        return None
    if not isinstance(value, str):
        value = str(value)
    return value[:max_length]


def validate_id(id_value):
    """Validate that an ID is a safe alphanumeric string."""
    if not isinstance(id_value, str):
        id_value = str(id_value)
    # Only allow alphanumeric characters and reasonable length
    if not id_value.isalnum() or len(id_value) > 64:
        return None
    return id_value


# Query resolvers
query = QueryType()


@query.field("me")
def resolve_me(_, info):
    """Resolve the currently authenticated user."""
    current_user = get_current_user_from_context(info)
    if current_user is None:
        return None
    user_id = validate_id(current_user.get("id", ""))
    if user_id is None:
        return None
    return USERS_DB.get(user_id)


@query.field("user")
def resolve_user(_, info, id):
    """Resolve a user by ID."""
    safe_id = validate_id(id)
    if safe_id is None:
        return None
    return USERS_DB.get(safe_id)


@query.field("users")
def resolve_users(_, info):
    """Resolve all users."""
    return list(USERS_DB.values())


