@user_type.field("posts")
def resolve_user_posts(user, info):
    """Resolve posts for a user. Only published posts are visible to others."""
    current_user = get_current_user_from_context(info)
    user_id = user.get("id")
    is_owner = current_user is not None and current_user.get("id") == user_id

    posts = [
        post for post in POSTS_DB.values()
        if post.get("author_id") == user_id
    ]

    if not is_owner:
        # Non-owners can only see published posts
        posts = [post for post in posts if post.get("published", False)]

    return posts


