# Authentication middleware
class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts authentication token from the Authorization header
    and sets current_user on the request state.
    
    Expected header format: Authorization: Bearer <token>
    """

    async def dispatch(self, request: Request, call_next):
        # Initialize current_user as None (unauthenticated)
        request.state.current_user = None

        auth_header = request.headers.get("Authorization", "")

        if auth_header.startswith("Bearer "):
            token = auth_header[7:].strip()

            # Validate token format (basic sanity check)
            if token and len(token) <= 256 and token.isascii():
                # Use constant-time comparison to prevent timing attacks
                for stored_token, user_id in TOKEN_TO_USER.items():
                    if hmac.compare_digest(token, stored_token):
                        user_data = USERS_DB.get(user_id)
                        if user_data:
                            # Only set safe, non-sensitive fields on the context
                            request.state.current_user = {
                                "id": user_data["id"],
                                "username": user_data["username"],
                            }
                        break

        response = await call_next(request)
        return response


# Query depth/complexity limiting middleware for GraphQL
# This helps prevent denial-of-service via deeply nested queries
MAX_QUERY_DEPTH = 10
MAX_QUERY_LENGTH = 10000  # Maximum query string length in characters


class QueryValidationMiddleware(BaseHTTPMiddleware):
    """Middleware to validate incoming GraphQL queries for basic safety."""

    async def dispatch(self, request: Request, call_next):
        if request.method == "POST" and request.url.path == "/graphql":
            # Check content length to prevent oversized payloads
            content_length = request.headers.get("content-length")
            if content_length and int(content_length) > MAX_QUERY_LENGTH * 2:
                from starlette.responses import JSONResponse
                return JSONResponse(
                    {"errors": [{"message": "Query too large"}]},
                    status_code=400,
                )

        response = await call_next(request)
        return response


